// Get module base from PEB
PVOID GetModuleFromPEB(LPCWSTR moduleName) {
    PPEB peb = (PPEB)__readgsqword(0x60);
    PLIST_ENTRY head = &peb->Ldr->InMemoryOrderModuleList;
    PLIST_ENTRY curr = head->Flink;

    do {
        PLDR_DATA_TABLE_ENTRY entry = CONTAINING_RECORD(curr, LDR_DATA_TABLE_ENTRY, InMemoryOrderLinks);
        if (entry->BaseDllName.Buffer) {
            if (_wcsicmp(entry->BaseDllName.Buffer, moduleName) == 0) {
                return entry->DllBase;
            }
        }
        curr = curr->Flink;
    } while (curr != head);

    return NULL;
}

// Get export by hash
PVOID GetExportByHash(PVOID moduleBase, DWORD hash) {
    PIMAGE_NT_HEADERS ntHeaders = (PIMAGE_NT_HEADERS)((BYTE*)moduleBase + ((PIMAGE_DOS_HEADER)moduleBase)->e_lfanew);
    PIMAGE_EXPORT_DIRECTORY exports = (PIMAGE_EXPORT_DIRECTORY)((BYTE*)moduleBase + ntHeaders->OptionalHeader.DataDirectory[0].VirtualAddress);

    DWORD* names = (DWORD*)((BYTE*)moduleBase + exports->AddressOfNames);
    WORD* ords = (WORD*)((BYTE*)moduleBase + exports->AddressOfNameOrdinals);
    DWORD* funcs = (DWORD*)((BYTE*)moduleBase + exports->AddressOfFunctions);

    for (DWORD i = 0; i < exports->NumberOfNames; i++) {
        char* name = (char*)((BYTE*)moduleBase + names[i]);
        if (HashString(name) == hash) {
            return (BYTE*)moduleBase + funcs[ords[i]];
        }
    }
    return NULL;
}

